#[cfg(test)]
mod tests {
    use super::*;
    use backbone_core::state_machine::StateMachineBehavior;

    #[test]
    fn test_initial_state() {
        let sm = MFADeviceStateMachine::default();
        assert_eq!(sm.current_state(), MFADeviceState::Pending);
        assert!(sm.current_state().is_initial());
    }

    #[test]
    fn test_valid_transition() {
        let mut sm = MFADeviceStateMachine { current_state: MFADeviceState::Pending };
        assert!(sm.can_transition(MFADeviceTransition::Verify));
        let result = sm.transition(MFADeviceTransition::Verify);
        assert!(result.is_ok());
        assert_eq!(sm.current_state(), MFADeviceState::Active);
    }

    #[test]
    fn test_invalid_transition() {
        let mut sm = MFADeviceStateMachine { current_state: MFADeviceState::Pending };
        // Disable is not valid from Pending state
        let result = sm.transition(MFADeviceTransition::Disable);
        assert!(result.is_err());
    }

    #[test]
    fn test_state_parsing() {
        let state: MFADeviceState = "pending".parse().unwrap();
        assert_eq!(state, MFADeviceState::Pending);
    }

    #[test]
    fn test_available_transitions() {
        let sm = MFADeviceStateMachine::default();
        let available = sm.available_transitions();
        // Should have at least some transitions available from initial state
        assert!(!available.is_empty() || sm.current_state().is_final());
    }
}
